query:
UPDATE establishments SET complement = CONCAT(IFNULL(complement, ''), IF(complement IS NOT NULL AND complement != '', '; ', ''), SUBSTRING_INDEX(address, ' - R.', 1)), address = CONCAT('Rua', SUBSTRING(address, LOCATE(' - R.', address) + 4)) WHERE address LIKE '% - R. %' AND address NOT REGEXP '^(Rua|Avenida|Alameda|Praça|Travessa|Largo|Estrada|Rodovia|Viela)';

UPDATE establishments SET complement = CONCAT(IFNULL(complement, ''), IF(complement IS NOT NULL AND complement != '', '; ', ''), SUBSTRING_INDEX(address, ' - Avenida', 1)), address = CONCAT('Avenida', SUBSTRING(address, LOCATE(' - Avenida', address) + 10)) WHERE address LIKE '% - Avenida %' AND address NOT REGEXP '^(Rua|Avenida|Alameda|Praça|Travessa|Largo|Estrada|Rodovia|Viela)';

UPDATE establishments SET complement = CONCAT(IFNULL(complement, ''), IF(complement IS NOT NULL AND complement != '', '; ', ''), SUBSTRING_INDEX(address, ' - Alameda', 1)), address = CONCAT('Alameda', SUBSTRING(address, LOCATE(' - Alameda', address) + 10)) WHERE address LIKE '% - Alameda %' AND address NOT REGEXP '^(Rua|Avenida|Alameda|Praça|Travessa|Largo|Estrada|Rodovia|Viela)';

